var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"좋아. 그럼 이제부터 작전의 개요를 설명할게.","JPN":"さあ、これから作戦の概要を説明するね。","ENG":"Anyway. Let me explain how this is going to work.","TWN":"好。那麼我現在來說明作戰計畫的概要。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"브레인 데스 작전은 공략이 어려운 적의 하드웨어 대신, 두뇌 역할을 하는 통제코어를 파괴해서 테라사이드 시스템 전체를 정지시키는 거야.","JPN":"ブレイン・デス作戦は、攻略が困難な敵のハードウェアの代わりに、\\n頭脳役の統制コアを破壊してテラサイドシステム全体を止めるものなの。","ENG":"Instead of striking the hard outer shell of the enemy, we're going to destroy the main control core, the \\"brain,\\" to bring the entire System Terraside to a halt.","TWN":"腦死作戰不是針對敵人難以攻略的硬體，而是破壞擔任大腦角色的控制核心，使特拉賽德系統整體停擺。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"말 그대로 뇌사상태로 만드는 거지.","JPN":"いわゆる脳死状態にするのよ。","ENG":"Hence the name, Brain Death.","TWN":"就像作戰名一樣，使敵人成為腦死狀態。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그게 불멸체 코어 아니었어?","JPN":"それが不滅体コアなんじゃないの？","ENG":"Isn't it the Immortal System Core that you're talking about?","TWN":"那不就是不滅者核心嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그것만 부수면 테라사이드 시스템이 붕괴한다고......","JPN":"それさえ壊せば、テラサイドシステムが崩壊するって……","ENG":"I heard that if we destroy that thing, the entire System Terraside would collapse.","TWN":"妳是說只要破壞了那個，特拉賽德系統就會崩壞……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"맞아. 하지만 불멸체 코어는 뉴 오하이오의 중추부에서 리플레이서 최고 간부들에게 보호받고 있다고.","JPN":"そうよ、でも不滅体コアはニューオハイオの中枢でリプレイサーの最高幹部らに守られているのよ。","ENG":"Correct. But that thing is guarded by the finest Replacer officers deep within the walls of the New Ohio.","TWN":"沒錯。但是不滅者核心在新俄亥俄的中樞，由克隆集團最高幹部保護著。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"애초에 그걸 부술 수 있다면 우리가 여기서 만날 이유도 없었겠지.","JPN":"それが破壊できてたら、私たちがここで会う理由もなかったでしょうね。","ENG":"If we could destroy it, we wouldn't have had to come all the way here.","TWN":"要是我從一開始就可以破壞掉它，我們就不會在這裡見面了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼?","JPN":"つまり？","ENG":"What are you saying?","TWN":"那現在？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"내가 알아낸 바에 따르면 테라사이드 시스템은 아무나 동작시킬 수 있는 게 아니야.","JPN":"私が調べた結果、テラサイドシステムは誰にでも動かせるものではない。","ENG":"According to my findings, System Terraside cannot be operated by just anybody.","TWN":"據我所知，特拉賽德系統不是誰都可以操作的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"애초에 불멸체 코어든 테라사이드 시스템이든, 기본 설계는 모두 로스트 쉽에 남겨진 구 관리국의 정보를 토대로 만들어 진 거야.","JPN":"そもそもの不滅体コアも、テラサイドシステムも、\\n基本設計はすべてロストシップに残された旧管理局の情報をベースに作られているのよ。","ENG":"Both the Immortal System Core and System Terraside were built based on the Old Administration's technology discovered in the Lost Ships.","TWN":"不管是不滅者核心，還是特拉賽德系統，當初都是以失落艦船上遺留的舊管理局資訊為基礎製造的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"당연히 해당 시스템에 명령을 내리려면 구 관리국의 시스템 통제용 어셈블리 코드를 만들어 낼 수 있어야 한다고.","JPN":"当然、そのシステムに命令するためには、\\n旧管理局のシステム統制用のアセンブリコードを生成しなければならないの。","ENG":"And they need the Old Administration's system control assembly code to give orders to the system.","TWN":"當然，要對那個系統下指令，就必須生成舊管理局系統控制用的彙編代碼。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"다시 말해, 통제코어가 없으면 테라사이드 시스템은 아무도 명령을 내릴 수 없는 멋진 고철더미에 불과하다는 뜻이지.","JPN":"言い換えれば、統制コアのないテラサイドシステムなんて、\\n誰の命令も受け付けない鉄の塊に過ぎないってことよ。","ENG":"That is, without the control core, System Terraside is nothing but a fancy-looking pile of junk that doesn't follow orders from anyone.","TWN":"換句話說，如果沒有控制核心，特拉賽德系統就只是一堆無法下達指令的廢鐵而已。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"그래? 그럼 당장 부수러 가자고!","JPN":"そうか、だったら今すぐぶち壊しに行こうぜ！","ENG":"Yeah? Then let's start smashing things up!","TWN":"是嗎？那我們現在就去破壞掉它！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"넌 제발 입 좀 다물어. 분위기 파악 좀 하고.","JPN":"あんたはちょっと黙っててよ。お願いだから少しは空気読んで。","ENG":"You just keep your mouth shut. Have some sense for once, for crying out loud.","TWN":"拜託妳閉嘴，看看氣氛好不好。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐야? 왜 날 바라보는 건데?","JPN":"何よ、何で見つめるのよ？","ENG":"Hmm? Why are you looking at me?","TWN":"怎麼了？你們盯著我幹嘛？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"통제코어는 그 특성상 테라사이드 시스템의 명령권자 역할을 겸임하고 있어.","JPN":"統制コアはその特性上、テラサイドシステムの命令権者の役割も兼ねているの。","ENG":"The control core, in its nature, also acts as the highest authority in System Terraside.","TWN":"控制核心在性質上，還兼任特拉賽德系統的命令權者。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"리플레이서에서는 그걸 <color=#ffd34c>의사결정권자</color>라고 불러.","JPN":"リプレイサーはそれを、<color=#ffd34c>意思決定権者</color>と呼んでいるのよ。","ENG":"And the Replacers call it the <color=#ffd34c>Arbiter</color>.","TWN":"克隆集團稱之為<color=#ffd34c>決策者</color>。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"의사결정권자......?","JPN":"意思決定権者……？","ENG":"The Arbiter?","TWN":"決策者……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 그거...... 설마?","JPN":"待って、それって……まさか？","ENG":"Wait, is that... No, it can't be!","TWN":"等等，那個……該不會？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그래. 네게서 추출한 클리포트 인자로 진화시킨 리플레이서 비숍 재생체가 바로......","JPN":"そう、あなたから抽出したクリフォト・ファクターで進化させた、リプレイサー・ビショップ再生体が……","ENG":"You're right. Bishop, the regenerated hybrider evolved by the Qliphoth Factor extracted from you...","TWN":"沒錯。用妳身上抽出的逆卡巴拉因子發生進化的克隆大主教再生體……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"테라사이드 시스템의 살아있는 통제 코어야.","JPN":"まさにテラサイドシステムの統制コアよ。","ENG":"She's the living control core of System Terraside.","TWN":"就是特拉賽德系統活生生的控制核心。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그래서 말인데...... 유미나, 너 리플레이서 비숍과 싸울 수 있겠어?","JPN":"そこでだけど、あなた……リプレイサー・ビショップと戦えるの？","ENG":"So I have to ask you this. Do you think you can fight Bishop, Yoo Mina?","TWN":"所以說……劉米娜，妳能和克隆大主教戰鬥嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"이 작전의 핵심은 너야.","JPN":"この作戦のカギを握るのはあなたよ。","ENG":"You're the most crucial part of this plan.","TWN":"這個作戰的核心就是妳。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"아무리 연산능력에 치우친 진화 재생체라고 해도 상대는 리플레이서 5대 간부 중의 한 명.","JPN":"演算能力に特化した進化再生体とはいえ、相手は5大リプレイサーの幹部の一人。","ENG":"Although Bishop isn't as talented in combat as she is in computing, she's still one of the five officers of the Replacer Syndicate.","TWN":"就算是專於演算能力的再生體，對方都是克隆集團5大幹部之一。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"일반적인 전력으로는 승산을 장담할 수 없어.","JPN":"通常の戦力では勝利を保障できない。","ENG":"She's a tough opponent even for skilled combatants,","TWN":"一般的戰鬥力很難有勝算。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"힐데 소대장이라도 있었으면 모를까......","JPN":"ヒルデ小隊長が不在の今……","ENG":"unless they have someone as strong as Commander Hilde in the team.","TWN":"希爾德小隊長要是在的話倒是不一定……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"우리들 중에 비숍을 단독으로 격파할 수 있는 건 너뿐이라고.","JPN":"私たちのなかでビショップをひとりで撃破できるのは、あなただけなのよ。","ENG":"You're the only one among us who could defeat Bishop without help.","TWN":"但我們之中能夠獨自擊敗大主教的就只有妳。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만...... 조금 전에 네가 날 이겼잖아?","JPN":"でも……さっき、私はあんたに負けたけど？","ENG":"But... I lost to you just a while ago.","TWN":"但是……妳剛剛不是贏過我了嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"바보 같은 소리 하지 마.","JPN":"冗談言わないでよ。","ENG":"Don't be stupid. I was taking a huge gamble when I faced you.","TWN":"別說傻話了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"내가 널 쓰러트린 건 미스틸테인의 상성관계를 이용한 도박이었다고.","JPN":"あれは、ミスティルテインの相性関係を利用した、一か八の賭けだったの。","ENG":"I could beat you down only because Misteltein was the most effective weapon against you; it was designed to absorb and reuse the Qliphoth Factor of the opponent. ","TWN":"我能打敗妳，是用米斯特丁下了一個賭注。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"비숍에겐 통하지 않을 거야.","JPN":"ビショップには通じないと思う。","ENG":"But it won't work with Bishop.","TWN":"但對大主教是行不通的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그러니까 여기서 확실히 말해.","JPN":"だから、ここでハッキリさせて。","ENG":"So I need you to make up your mind.","TWN":"所以請妳在這裡確實地說清楚。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"비숍을 쓰러트릴 수 있겠어?","JPN":"ビショップを倒す自信はある？","ENG":"Can you bring Bishop down?","TWN":"妳能打敗大主教嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"걱정 마, 내게 맡겨.","JPN":"もちろん、私に任せて。","ENG":"Leave it to me.","TWN":"別擔心，交給我。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"날 속인 그 녀석에겐...... 갚아줘야 할 빚도 있으니까.","JPN":"私を騙したあいつには……借りを返してやらなきゃ。","ENG":"She fooled me, and she's going to pay for it.","TWN":"那個傢伙騙了我……她一定要付出代價。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"좋아. 이해하고 있는 것 같아서 다행이네.","JPN":"よし、理解しているみたいで良かった。","ENG":"Good. I'm glad you realize the gravity of this.","TWN":"很好，妳能理解了真是太好了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......그런데.","JPN":"……ところで。","ENG":"But just to be sure...","TWN":"……但是。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내가 녀석과의 싸움에서 이기면......","JPN":"もし、私が奴に勝ったら……","ENG":"If I win,","TWN":"在我打贏她的時候……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그땐 녀석을 죽여야만 하는 거지?","JPN":"最後は殺さなきゃいけないよね？","ENG":"would I have to kill her?","TWN":"就只能殺了那傢伙嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"지금으로선 그게 우리가 선택할 수 있는 최선이야.","JPN":"今の状況ではそれがベストね。","ENG":"That's the best and only choice we have.","TWN":"這是我們目前最好的選擇了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"이번에 우리가 비숍을 먼저 처리하지 않으면 다음 기회는 없어.","JPN":"私たちがビショップを討てるチャンスは、今回限りだから。","ENG":"If we don't take care of her this time, there won't be a second chance.","TWN":"這次我們不先處理掉大主教的話，就沒有下一次的機會了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"......그리고 혼동하지 마. 그건 더 이상 네 친구가 아니니까.","JPN":"……それに、くれぐれも勘違いしないようにね。あれは、もはやあなたの友人ではない。","ENG":"Don't be confused. She isn't your friend anymore.","TWN":"……還有，別搞錯了。她已經不是妳的朋友了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래, 알고 있어. 그런 것쯤은......","JPN":"うん、わかってるよ。それくらいは……","ENG":"Yes, I know that. I know she's no longer my friend...","TWN":"是，這我還是知道的……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그런 우유부단한 태도는 마음에 안 들지만.....","JPN":"そういう優柔不断な姿勢は気に食わないけど……","ENG":"I can see that you're indecisive, and I don't like it,","TWN":"雖然我不喜歡妳這種優柔寡斷的態度……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"마냥 여기서 널 설득하고 있을 만큼 우리가 여유롭진 않아.","JPN":"これ以上説得に時間を割く暇はない。","ENG":"but we don't have the luxury to talk sense into you now.","TWN":"但現在也沒有時間在這裡開導妳了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그러니 마음 단단히 먹길 바랄게.","JPN":"あなたが覚悟を決めてくれることを願ってるよ。","ENG":"So please, prepare yourself.","TWN":"所以希望妳能下定決心。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......응.","JPN":"……うん。","ENG":"I will.","TWN":"……嗯。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"자! 지금부터 우린 리플레이서 비숍 재생체를 처치하러 간다.","JPN":"よし！　さあ、今からリプレイサー・ビショップ再生体を倒しに行きましょう！","ENG":"Now, we're about to go in for the kill on the Regenerated Bishop.","TWN":"好了！現在我們就去打倒克隆大主教再生體。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"녀석이 있을 만한 곳은 이미 확인해뒀어.","JPN":"奴の居場所はあらかじめ確認しておいたの。","ENG":"I've already checked where she might be.","TWN":"我已經確認了她的所在位置。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"왜인지는 모르겠지만...... 리플레이서 비숍 재생체는 며칠 전부터 뉴 오하이오와 멀리 떨어진 스텔스 필드의 끝자락에 홀로 앉아 있는 시간이 많아.","JPN":"理由はわからないけど……リプレイサー・ビショップ再生体はここのところ、\\nニューオハイオから遠く離れた、ステルスフィールドの端にひとりでいることが多い。","ENG":"I don't know why, but since a few days ago, she's been sighted sitting by herself at the edge of the stealth field, far away from the New Ohio.","TWN":"不知道為什麼……克隆大主教再生體從幾天前，就遠離了新俄亥俄，一個人待在隱形場域的角落。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"호위 병력도 최소한으로만 대동하고 있고, 무엇보다 다른 간부들과도 멀리 떨어져 있지.","JPN":"付き添いの兵士も必要最低限の人数のみで、何より他の幹部からも遠く離れてる。","ENG":"She doesn't bring a whole lot of escorts with her, and more importantly, she's away from the rest of the officers when she's there.","TWN":"不但只有最低限度的護衛陪同，更重要的是，離其他幹部們還很遠。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"이 정도면 목표를 처치하기 최적의 조건이야.","JPN":"ターゲットを始末するための条件が揃ってるの。","ENG":"In short, that's our best chance to attack.","TWN":"這是我們擊敗目標的最佳條件。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그럼 다들, 출발한다!","JPN":"さあ、みんな、出発しよう！","ENG":"Let's roll out, everyone.","TWN":"那麼，出發吧！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};